DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM pg_namespace WHERE nspname = 'ida') THEN
        CREATE SCHEMA ida;
    END IF;
END $EF$;


CREATE TABLE ida.aplicacao (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Nome" character varying(200) NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_aplicacao" PRIMARY KEY ("Id")
);


CREATE TABLE ida.area (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Nome" character varying(200) NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_area" PRIMARY KEY ("Id")
);


CREATE TABLE ida.cliente (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Nome" character varying(200) NOT NULL,
    "Cnpj" character varying(14) NOT NULL,
    "Email" character varying(200) NOT NULL,
    "Telefone" character varying(14) NOT NULL,
    "Foto" bytea,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_cliente" PRIMARY KEY ("Id")
);


CREATE TABLE ida.log_auditoria (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Usuario" character varying(200) NOT NULL,
    "Acao" character varying(50) NOT NULL,
    "Tabela" character varying(100) NOT NULL,
    "DadosAntigos" text NOT NULL,
    "DadosNovos" text NOT NULL,
    "DataHora" timestamp without time zone NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_log_auditoria" PRIMARY KEY ("Id")
);


CREATE TABLE ida.modelo_controle (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Nome" character varying(200) NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_modelo_controle" PRIMARY KEY ("Id")
);


CREATE TABLE ida.role (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Nome" character varying(200) NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_role" PRIMARY KEY ("Id")
);


CREATE TABLE ida.pessoa (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Nome" character varying(200) NOT NULL,
    "Cpf" character varying(11) NOT NULL,
    "Email" character varying(200) NOT NULL,
    "Telefone" character varying(14) NOT NULL,
    "Foto" bytea,
    "DataNascimento" timestamp without time zone,
    "IdCliente" bigint,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_pessoa" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_pessoa_cliente_IdCliente" FOREIGN KEY ("IdCliente") REFERENCES ida.cliente ("Id")
);


CREATE TABLE ida.cliente_modelo_controle (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "IdCliente" bigint NOT NULL,
    "IdModeloControle" bigint NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_cliente_modelo_controle" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_cliente_modelo_controle_cliente_IdCliente" FOREIGN KEY ("IdCliente") REFERENCES ida.cliente ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_cliente_modelo_controle_modelo_controle_IdModeloControle" FOREIGN KEY ("IdModeloControle") REFERENCES ida.modelo_controle ("Id") ON DELETE CASCADE
);


CREATE TABLE ida.cargo (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Nome" character varying(200) NOT NULL,
    "IdRole" bigint NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_cargo" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_cargo_role_IdRole" FOREIGN KEY ("IdRole") REFERENCES ida.role ("Id") ON DELETE CASCADE
);


CREATE TABLE ida.role_aplicacao (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "IdRole" bigint NOT NULL,
    "IdAplicacao" bigint NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_role_aplicacao" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_role_aplicacao_aplicacao_IdAplicacao" FOREIGN KEY ("IdAplicacao") REFERENCES ida.aplicacao ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_role_aplicacao_role_IdRole" FOREIGN KEY ("IdRole") REFERENCES ida.role ("Id") ON DELETE CASCADE
);


CREATE TABLE ida.cargo_area (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "IdCargo" bigint NOT NULL,
    "IdArea" bigint NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_cargo_area" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_cargo_area_area_IdArea" FOREIGN KEY ("IdArea") REFERENCES ida.area ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_cargo_area_cargo_IdCargo" FOREIGN KEY ("IdCargo") REFERENCES ida.cargo ("Id") ON DELETE CASCADE
);


CREATE TABLE ida.cliente_cargo (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "IdCliente" bigint NOT NULL,
    "IdCargo" bigint NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_cliente_cargo" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_cliente_cargo_cargo_IdCargo" FOREIGN KEY ("IdCargo") REFERENCES ida.cargo ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_cliente_cargo_cliente_IdCliente" FOREIGN KEY ("IdCliente") REFERENCES ida.cliente ("Id") ON DELETE CASCADE
);


CREATE TABLE ida.usuario (
    "Id" bigint NOT NULL,
    "Login" character varying(200) NOT NULL,
    "Senha" character varying(255) NOT NULL,
    "FlAtivo" boolean NOT NULL DEFAULT TRUE,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    "IdCargo" bigint NOT NULL,
    CONSTRAINT "PK_usuario" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_usuario_cargo_IdCargo" FOREIGN KEY ("IdCargo") REFERENCES ida.cargo ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_usuario_pessoa_Id" FOREIGN KEY ("Id") REFERENCES ida.pessoa ("Id") ON DELETE CASCADE
);


CREATE TABLE ida.cliente_usuario (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "IdCliente" bigint NOT NULL,
    "IdUsuario" bigint NOT NULL,
    "IdArea" bigint NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_cliente_usuario" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_cliente_usuario_area_IdArea" FOREIGN KEY ("IdArea") REFERENCES ida.area ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_cliente_usuario_cliente_IdCliente" FOREIGN KEY ("IdCliente") REFERENCES ida.cliente ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_cliente_usuario_usuario_IdUsuario" FOREIGN KEY ("IdUsuario") REFERENCES ida.usuario ("Id") ON DELETE CASCADE
);


CREATE TABLE ida.lancamento (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    id_usuario bigint NOT NULL,
    id_modelo_controle bigint NOT NULL,
    data_lancamento timestamp without time zone NOT NULL DEFAULT (now()),
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_lancamento" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_lancamento_modelo_controle_id_modelo_controle" FOREIGN KEY (id_modelo_controle) REFERENCES ida.modelo_controle ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_lancamento_usuario_id_usuario" FOREIGN KEY (id_usuario) REFERENCES ida.usuario ("Id") ON DELETE CASCADE
);


CREATE TABLE ida.notificacao (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Titulo" character varying(200) NOT NULL,
    "Mensagem" text NOT NULL,
    "Lida" boolean NOT NULL,
    "IdUsuarioDestino" bigint NOT NULL,
    "Tipo" text NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_notificacao" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_notificacao_usuario_IdUsuarioDestino" FOREIGN KEY ("IdUsuarioDestino") REFERENCES ida.usuario ("Id") ON DELETE CASCADE
);


CREATE TABLE ida.usuario_area (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "IdUsuario" bigint NOT NULL,
    "IdArea" bigint NOT NULL,
    "DtUltimaAtualizacao" timestamp without time zone NOT NULL DEFAULT (now()),
    CONSTRAINT "PK_usuario_area" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_usuario_area_area_IdArea" FOREIGN KEY ("IdArea") REFERENCES ida.area ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_usuario_area_usuario_IdUsuario" FOREIGN KEY ("IdUsuario") REFERENCES ida.usuario ("Id") ON DELETE CASCADE
);


CREATE TABLE ida.lancamento_cadastro (
    "Id" bigint NOT NULL,
    qtd_click_link bigint NOT NULL,
    qtd_cadastros bigint NOT NULL,
    vlr_ticket_medio numeric(38,2) NOT NULL,
    vlr_investimento_meta numeric(38,2) NOT NULL,
    vlr_investimento_google numeric(38,2) NOT NULL,
    CONSTRAINT "PK_lancamento_cadastro" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_lancamento_cadastro_lancamento_Id" FOREIGN KEY ("Id") REFERENCES ida.lancamento ("Id") ON DELETE CASCADE
);


CREATE TABLE ida.lancamento_saude (
    "Id" bigint NOT NULL,
    qtd_click_meta bigint NOT NULL,
    qtd_click_google bigint NOT NULL,
    qtd_contatos_reais bigint NOT NULL,
    qtd_conversao_consultas bigint NOT NULL,
    vlr_ticket_medio_consultas numeric(38,2),
    qtd_entrada_redes_sociais bigint NOT NULL,
    qtd_entrada_google bigint NOT NULL,
    vlr_investimento_meta numeric(38,12),
    vlr_investimento_google numeric(38,2),
    CONSTRAINT "PK_lancamento_saude" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_lancamento_saude_lancamento_Id" FOREIGN KEY ("Id") REFERENCES ida.lancamento ("Id") ON DELETE CASCADE
);


CREATE TABLE ida.lancamento_varejo (
    "Id" bigint NOT NULL,
    qtd_atendimento bigint NOT NULL,
    qtd_fechamento bigint NOT NULL,
    faturamento numeric(38,2) NOT NULL,
    qtd_instagram bigint NOT NULL,
    qtd_facebook bigint NOT NULL,
    qtd_google bigint NOT NULL,
    qtd_indicacao bigint NOT NULL,
    vlr_investimento_meta numeric(38,2) NOT NULL,
    vlr_investimento_google numeric(38,2) NOT NULL,
    CONSTRAINT "PK_lancamento_varejo" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_lancamento_varejo_lancamento_Id" FOREIGN KEY ("Id") REFERENCES ida.lancamento ("Id") ON DELETE CASCADE
);


