SELECT setval(
    pg_get_serial_sequence('ida.aplicacao', 'Id'),
    GREATEST(
        (SELECT MAX("Id") FROM ida.aplicacao) + 1,
        nextval(pg_get_serial_sequence('ida.aplicacao', 'Id'))),
    false);
SELECT setval(
    pg_get_serial_sequence('ida.area', 'Id'),
    GREATEST(
